#pragma once

#include <cmath>
#include <arbor/version.hpp>
#include <arbor/mechanism_abi.h>

extern "C" {
  arb_mechanism_type make_arb_efields_catalogue_reader_type() {
    // Tables
    static arb_field_info globals[] = {{ "field", "", NAN, -.000000, .000000 } };
    static arb_size_type n_globals = 1;
    static arb_field_info state_vars[] = {{ "da", "", NAN, -.000000, .000000 } };
    static arb_size_type n_state_vars = 1;
    static arb_field_info parameters[] = {{ "xp", "", NAN, -.000000, .000000 },
        { "yp", "", NAN, -.000000, .000000 },
        { "zp", "", NAN, -.000000, .000000 },
        { "xd", "", NAN, -.000000, .000000 },
        { "yd", "", NAN, -.000000, .000000 },
        { "zd", "", NAN, -.000000, .000000 } };
    static arb_size_type n_parameters = 6;
    static arb_ion_info* ions = NULL;
    static arb_size_type n_ions = 0;
    static arb_random_variable_info* random_variables = NULL;
    static arb_size_type n_random_variables = 0;

    arb_mechanism_type result;
    result.abi_version=ARB_MECH_ABI_VERSION;
    result.fingerprint="<placeholder>";
    result.name="reader";
    result.kind=arb_mechanism_kind_point;
    result.is_linear=true;
    result.has_post_events=false;
    result.globals=globals;
    result.n_globals=n_globals;
    result.ions=ions;
    result.n_ions=n_ions;
    result.state_vars=state_vars;
    result.n_state_vars=n_state_vars;
    result.parameters=parameters;
    result.n_parameters=n_parameters;
    result.random_variables=random_variables;
    result.n_random_variables=n_random_variables;
    return result;
  }

  arb_mechanism_interface* make_arb_efields_catalogue_reader_interface_multicore();
  arb_mechanism_interface* make_arb_efields_catalogue_reader_interface_gpu();

  #ifndef ARB_GPU_ENABLED
  arb_mechanism_interface* make_arb_efields_catalogue_reader_interface_gpu() { return nullptr; }
  #endif

  arb_mechanism make_arb_efields_catalogue_reader() {
    static arb_mechanism result = {};
    result.type  = make_arb_efields_catalogue_reader_type;
    result.i_cpu = make_arb_efields_catalogue_reader_interface_multicore;
    result.i_gpu = make_arb_efields_catalogue_reader_interface_gpu;
    return result;
  }
} // extern C
